const e={title:"أجهزة مطبخ مدمجة فاخرة | مخطط مطبخ LG",description:"حوّل مساحتك الطهوية بمواقد LG المدمجة الفاخرة، وشفاطات ThinQ، وأفران InstaView الذكية."},t={title:"تجربة أجهزة إل جي المدمجة",subtitle:"انغمس في تجربة أجهزة إل جي المدمجة: تفاعل مع المطبخ كما في الواقع.",experienceButton:"اختبر الآن",quoteButton:"طلب عرض أسعار المؤسسة"},a={title:"مدونة المطبخ",subtitle:"اكتشف وصفات لذيذة ونصائح الخبراء وقصص المطبخ الملهمة مع تجربة أجهزة إل جي المدمجة",learnMore:"اعرف اكثر"},s={title:"خدماتنا",installationGuides:{cardTitle:"تحكم في مطبخك: دليل التثبيت خطوة بخطوة لمنتجات إل جي المدمجة",description:"قم بتحويل مساحتك بسهولة مع نصائح وحيل التثبيت الاحترافية للحصول على تجربة سلسة مع أجهزة إل جي المدمجة",button:"اعرف اكثر",imageAlt:"تحكم في مطبخك: دليل التثبيت خطوة بخطوة لمنتجات إل جي المدمجة"},eCatalogue:{cardTitle:"كتالوج إلكتروني لتجربة المطبخ المدمج من إل جي",description:"اكتشف الأجهزة المتطورة والوصفات المبتكرة ونصائح الخبراء لرحلة الطهي المثالية",button:"اعرف المزيد",imageAlt:"كتالوج إلكتروني لتجربة المطبخ المدمج من إل جي"}},n={sectionTitle:"الأسئلة الشائعة",sectionDescription:"استكشف الأسئلة الشائعة حول الأجهزة المدمجة من إل جي، والتي توفر أفكارا وحلولأ سريعة لضمان التشغيل السلس والرضا.",learnMore:"اعرف المزيد",viewAll:"اعرف المزيد",continueReading:"متابعة القراءة",items:[{questionUser:{name:"حسين",role:"خبير الخبز",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/henry.png",avatarAlt:"حسين"},question:"ماذا لو كنت تريد تغيير مطبخك بمنتجات إل جي المدمجة؟",answerUser:{name:"خدمة العملاء",role:"خبير الأجهزة المدمجة من إل جي",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/Life's%20Good%20Logo.png",avatarAlt:"خدمة العملاء"},answer:"إذا كان المنتج مدمجًا (فرن غاز، موقد طهي)، فيجب تركيبه وفقًا لأثاث المطبخ، لذا يجب عليك الاتصال بشركة أثاث المطبخ أو شركة تصميم داخلي للتحقق من نوع وحجم أثاث المطبخ. بعد الاستشارة، إذا تم تأمين مساحة التثبيت للمنتج المدمج، يمكنك طلب من شركة أثاث المطبخ تثبيت منتج إل جي المدمج. (حاليًا، يمكنك الاستفسار عن وشراء منتجات LG المدمجة في متجر LG Premium Brandshop ومتاجر وكلاء العلامات التجارية المتعددة ومتاجر التصميم الداخلي للمطبخ)."},{questionUser:{name:"فاطمة",role:"مضيفة منزلية",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/jj.png",avatarAlt:"فاطمة"},question:"هل يمكنني استخدام غسالة الصحون المدمجة دون دمجها مع الأثاث؟",answerUser:{name:"خدمة العملاء",role:"خبير الأجهزة المدمجة من إل جي",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/Life's%20Good%20Logo.png",avatarAlt:"خدمة العملاء"},answer:`لا توجد أي مشكلة على الإطلاق في استخدام المنتج. ومع ذلك، نظرًا لأن المنتجات المدمجة يتم تصنيعها لدمجها مع الأثاث، فإذا لم يتم دمج الأثاث، فلن يخرج الجسم نفسه كمنتج نهائي، مما يجعله غير جذاب من الناحية البصرية. 
يرجى وضع هذا في الاعتبار.`},{questionUser:{name:"خالد",role:"رئيس الطهاة",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/nora.png",avatarAlt:"خالد"},question:"هل من المستحيل استبداله بعد تثبيته؟",answerUser:{name:"خدمة العملاء",role:"خبير الأجهزة المدمجة من إل جي",avatar:"https://lgkitchenplanner.com/sa_en/assets/images/faq/Life's%20Good%20Logo.png",avatarAlt:"خدمة العملاء"},answer:"من الممكن استبدال المنتج بعد التثبيت. يمكنك إعادة تثبيت المنتج طالما أن مساحة التثبيت المدمجة مؤمنة."}]},o={title:"المنتجات الموصى بها",viewAll:"اعرف المزيد",buyNow:"اشتري الآن"},i={sectionTitle:"استكشف تصاميم المطابخ",sectionSubtitle:"اكتشف كيف تندمج أجهزة LG المدمجة بجمال في كل تصميم مطبخ."},r={metadata:e,hero:t,blog:a,services:s,faq:n,recommendedProducts:o,kitchenLayouts:i};export{a as blog,r as default,n as faq,t as hero,i as kitchenLayouts,e as metadata,o as recommendedProducts,s as services};
